def apply_pagination(items, first=None, offset=None):
    if offset is None:
        offset = 0
    if offset < 0:
        offset = 0
    sliced = items[offset:]
    if first is not None:
        if first < 0:
            first = 0
        sliced = sliced[:first]
    return sliced

