    def resolve_reviews(root, info, first=None, offset=None, product_id=None, min_rating=None):
        items = REVIEWS[:]
        if product_id is not None:
            items = [r for r in items if r["product_id"] == product_id]
        if min_rating is not None:
            items = [r for r in items if r["rating"] >= min_rating]
        return apply_pagination(items, first=first, offset=offset)

